// Parse OpenAI response and extract patient data
const response = $input.first().json;
let patientData;

try {
  // Handle OpenAI response structure
  if (response.choices && response.choices[0] && response.choices[0].message) {
    patientData = JSON.parse(response.choices[0].message.content);
  } else if (response.body && response.body.choices) {
    patientData = JSON.parse(response.body.choices[0].message.content);
  } else {
    patientData = response;
  }
} catch (e) {
  patientData = {
    error: 'Failed to parse AI response',
    raw_response: response
  };
}

// Add timestamp and booking reference
const now = new Date();
const bookingRef = 'DAC-' + now.getFullYear() + 
  String(now.getMonth() + 1).padStart(2, '0') + 
  String(now.getDate()).padStart(2, '0') + '-' + 
  String(now.getHours()).padStart(2, '0') + 
  String(now.getMinutes()).padStart(2, '0') + 
  String(now.getSeconds()).padStart(2, '0');

// Calculate end time (30 min for regular, 60 min for complex procedures)
let appointmentDuration = 30;
const complexProcedures = ['root_canal', 'extraction', 'braces'];
if (complexProcedures.includes(patientData.appointment_type)) {
  appointmentDuration = 60;
}

let endTime = null;
if (patientData.preferred_time) {
  const [hours, minutes] = patientData.preferred_time.split(':').map(Number);
  const endMinutes = (hours * 60 + minutes + appointmentDuration) % 1440;
  endTime = String(Math.floor(endMinutes / 60)).padStart(2, '0') + ':' + 
            String(endMinutes % 60).padStart(2, '0');
}

return {
  json: {
    ...patientData,
    booking_reference: bookingRef,
    created_at: now.toISOString(),
    appointment_end_time: endTime,
    appointment_duration: appointmentDuration,
    status: 'pending',
    clinic_name: 'Dr. Ahmed Dental Care',
    clinic_address: 'Main Boulevard, Gulberg III, Lahore',
    clinic_phone: '042-35761234'
  }
};

// Check if the preferred time slot is available
const items = $input.all();
const patientData = $('⚙️ Parse AI Response').first().json;

const preferredDate = patientData.preferred_date;
const preferredTime = patientData.preferred_time;
const duration = patientData.appointment_duration || 30;

// Parse preferred time
const [prefHours, prefMinutes] = preferredTime.split(':').map(Number);
const preferredStart = new Date(`${preferredDate}T${preferredTime}:00`);
const preferredEnd = new Date(preferredStart.getTime() + duration * 60000);

let isAvailable = true;
let conflictingEvent = null;

// Check each existing event for conflicts
for (const item of items) {
  if (item.json.start && item.json.end) {
    const eventStart = new Date(item.json.start.dateTime || item.json.start.date);
    const eventEnd = new Date(item.json.end.dateTime || item.json.end.date);

    // Check for overlap
    if (preferredStart < eventEnd && preferredEnd > eventStart) {
      isAvailable = false;
      conflictingEvent = item.json.summary;
      break;
    }
  }
}

// Suggest alternative times if not available
let suggestedTimes = [];
if (!isAvailable) {
  const alternatives = ['09:00', '10:00', '11:00', '14:00', '15:00', '16:00', '17:00'];
  for (const time of alternatives) {
    if (time !== preferredTime) {
      suggestedTimes.push(time);
    }
  }
}

return {
  json: {
    ...patientData,
    is_slot_available: isAvailable,
    conflicting_event: conflictingEvent,
    suggested_alternative_times: suggestedTimes.slice(0, 3)
  }
};

